import json

with open('/private/tmp/claude-501/-Users-bhyslop-projects-rbm-alpha-recipemuster/tasks/aa2f0443094fc5a3f.output', 'r') as f:
    lines = f.readlines()

# Dump type of each line to understand structure
for i, line in enumerate(lines):
    try:
        obj = json.loads(line.strip())
        t = obj.get('type', '?')
        # For assistant lines, check content structure
        extra = ''
        if t == 'assistant':
            content = obj.get('message', {}).get('content', '')
            if isinstance(content, list):
                types = [b.get('type','?') for b in content if isinstance(b, dict)]
                extra = f' blocks={types}'
            else:
                extra = f' str len={len(content)}'
        elif t == 'tool_result':
            content = obj.get('content', '')
            if isinstance(content, str):
                extra = f' str len={len(content)}'
            elif isinstance(content, list):
                for b in content:
                    if isinstance(b, dict):
                        extra += f' {b.get(\"type\",\"?\")}({len(b.get(\"text\",b.get(\"content\",\"\")))})'
        print(f'Line {i+1}: type={t}{extra}')
    except Exception as e:
        print(f'Line {i+1}: parse error: {e}')
